```tsx
// ═══ 1. 풀 투 리프레시 + 스켈레톤 ═══
function FeedScreen() {
  const { data, isLoading, refetch, isRefetching } = useQuery({
    queryKey: ["feed"],
    queryFn: fetchFeed,
  });

  if (isLoading) return <FeedSkeleton />;

  return (
    <ScrollView
      refreshControl={
        <RefreshControl
          refreshing={isRefetching}
          onRefresh={refetch}
          tintColor="#3b82f6"
        />
      }
