            { 오류: "이름과 이메일은 필수입니다" },
            { status: 400 }
        );
    }

    // DB 저장 로직
    const 새사용자 = {
        id: Date.now().toString(),
        이름: 데이터.이름,
        이메일: 데이터.이메일,
    };

    return Response.json(새사용자, { status: 201 });
}
