메타클래스는 "클래스를 만드는 클래스"입니다. 프레임워크에서 자주 씁니다.

```python
# ═══ 메타클래스 기초 ═══
# 모든 클래스는 type의 인스턴스
print(type(int))       # <class 'type'>
print(type(str))       # <class 'type'>

class MyClass:
    pass

print(type(MyClass))   # <class 'type'>
# MyClass = type("MyClass", (), {})  와 동일

# ═══ 1. 싱글톤 메타클래스 ═══
class SingletonMeta(type):
    _instances = {}

    def __call__(cls, *args, **kwargs):
        if cls not in cls._instances:
            cls._instances[cls] = super().__call__(*args, **kwargs)
        return cls._instances[cls]

class Database(metaclass=SingletonMeta):
    def __init__(self, url="localhost"):
        self.url = url
        self.connected = True

db1 = Database("postgresql://localhost")
db2 = Database("다른 URL")
print(db1 is db2)  # True (같은 인스턴스)

# ═══ 2. 자동 등록 메타클래스 (플러그인 시스템) ═══
class PluginRegistry(type):
    plugins: dict[str, type] = {}

    def __init_subclass__(cls, **kwargs):
        super().__init_subclass__(**kwargs)
        # 등록 로직은 __init__에서 처리

    def __new__(mcs, name, bases, namespace):
        cls = super().__new__(mcs, name, bases, namespace)
        if bases:  # 베이스 클래스(Plugin) 자체는 제외
            PluginRegistry.plugins[name.lower()] = cls
        return cls

class Plugin(metaclass=PluginRegistry):
    def execute(self):
        raise NotImplementedError

class EmailPlugin(Plugin):
    def execute(self):
        return "이메일 발송"

class SlackPlugin(Plugin):
    def execute(self):
        return "슬랙 메시지"

# 자동 등록됨!
print(PluginRegistry.plugins)
# {'emailplugin': <class 'EmailPlugin'>, 'slackplugin': <class 'SlackPlugin'>}

# 이름으로 플러그인 생성
def create_plugin(name: str) -> Plugin:
    cls = PluginRegistry.plugins.get(name.lower())
    if not cls:
        raise ValueError(f"플러그인 없음: {name}")
    return cls()

plugin = create_plugin("email")
plugin.execute()  # "이메일 발송"

# ═══ 3. 필드 검증 메타클래스 (ORM 스타일) ═══
class Field:
    def __init__(self, field_type, required=False, default=None):
        self.field_type = field_type
        self.required = required
        self.default = default

class ModelMeta(type):
    def __new__(mcs, name, bases, namespace):
        fields = {}
        for key, value in namespace.items():
            if isinstance(value, Field):
                fields[key] = value

        namespace["_fields"] = fields
        cls = super().__new__(mcs, name, bases, namespace)
        return cls

class Model(metaclass=ModelMeta):
    def __init__(self, **kwargs):
        for name, field in self._fields.items():
            value = kwargs.get(name, field.default)
            if field.required and value is None:
                raise ValueError(f"{name}은(는) 필수입니다")
            if value is not None and not isinstance(value, field.field_type):
                raise TypeError(f"{name}: {field.field_type.__name__} 타입이어야 합니다")
            setattr(self, name, value)

    def to_dict(self):
        return {name: getattr(self, name) for name in self._fields}

# 사용 (Django/SQLAlchemy 느낌)
class User(Model):
    name = Field(str, required=True)
    email = Field(str, required=True)
    age = Field(int, default=0)
    role = Field(str, default="user")

user = User(name="홍길동", email="hong@test.com", age=28)
print(user.to_dict())
# {'name': '홍길동', 'email': 'hong@test.com', 'age': 28, 'role': 'user'}

# User(name="홍길동", email=123)  → TypeError!
# User(email="hong@test.com")    → ValueError! (name 필수)

# ═══ 4. 실무에서 더 좋은 대안 ═══
# 메타클래스 대신 __init_subclass__ (Python 3.6+)

class Plugin:
    _registry: dict[str, type] = {}

    def __init_subclass__(cls, name: str = None, **kwargs):
        super().__init_subclass__(**kwargs)
        plugin_name = name or cls.__name__.lower()
        Plugin._registry[plugin_name] = cls

    @classmethod
    def create(cls, name: str):
        return cls._registry[name]()

class EmailPlugin(Plugin, name="email"):
    def run(self): return "이메일"

class SlackPlugin(Plugin, name="slack"):
    def run(self): return "슬랙"

plugin = Plugin.create("email")

# 또는 데코레이터로 더 간단하게
registry = {}

def register(name):
    def decorator(cls):
        registry[name] = cls
        return cls
    return decorator

@register("email")
class EmailHandler:
    def handle(self): return "이메일 처리"
```

메타클래스 사용 기준:
| 상황 | 권장 방법 |
|------|-----------|
| 간단한 등록 | `__init_subclass__` 또는 데코레이터 |
| ORM 필드 정의 | 메타클래스 또는 디스크립터 |
| 싱글톤 | `__new__` 오버라이드 또는 모듈 레벨 |
| API 검증 | Pydantic (메타클래스 내부 사용) |
| 프레임워크 개발 | 메타클래스 (Django, SQLAlchemy 내부) |

실무 원칙: **메타클래스는 최후의 수단**. `__init_subclass__`, 데코레이터, 디스크립터로 충분하면 그쪽을 사용.

디스크립터는 `property`, `classmethod`, `staticmethod`의 내부 원리입니다.

```python
# ═══ 디스크립터 프로토콜 ═══
# __get__, __set__, __delete__ 중 하나라도 구현하면 디스크립터

# 1. 데이터 디스크립터 (__get__ + __set__)
class TypedField:
    """타입을 검증하는 디스크립터."""

    def __init__(self, name: str, field_type: type, default=None):
        self.name = name
        self.field_type = field_type
        self.default = default

    def __set_name__(self, owner, name):
        """클래스에 할당될 때 호출 (Python 3.6+)."""
        self.name = name
        self.storage_name = f"_desc_{name}"

    def __get__(self, obj, objtype=None):
        if obj is None:
            return self  # 클래스에서 접근 시 디스크립터 자체 반환
        return getattr(obj, self.storage_name, self.default)

    def __set__(self, obj, value):
        if not isinstance(value, self.field_type):
            raise TypeError(
                f"{self.name}: {self.field_type.__name__} 타입이어야 합니다, "
                f"받은 값: {type(value).__name__}"
            )
        setattr(obj, self.storage_name, value)

    def __delete__(self, obj):
        delattr(obj, self.storage_name)

class User:
    name = TypedField("name", str)
    age = TypedField("age", int, default=0)
    email = TypedField("email", str)

user = User()
user.name = "홍길동"      # ✅ OK
user.age = 28              # ✅ OK
# user.age = "스물여덟"   # ❌ TypeError!

# 2. property의 실제 구현 (디스크립터)
class Property:
    """property 빌트인의 순수 파이썬 구현."""

    def __init__(self, fget=None, fset=None, fdel=None, doc=None):
        self.fget = fget
        self.fset = fset
        self.fdel = fdel
        self.__doc__ = doc or (fget.__doc__ if fget else None)

    def __get__(self, obj, objtype=None):
        if obj is None:
            return self
        if self.fget is None:
            raise AttributeError("읽기 불가")
        return self.fget(obj)

    def __set__(self, obj, value):
        if self.fset is None:
            raise AttributeError("쓰기 불가")
        self.fset(obj, value)

    def __delete__(self, obj):
        if self.fdel is None:
            raise AttributeError("삭제 불가")
        self.fdel(obj)

    def getter(self, fget):
        return type(self)(fget, self.fset, self.fdel, self.__doc__)

    def setter(self, fset):
        return type(self)(self.fget, fset, self.fdel, self.__doc__)

    def deleter(self, fdel):
        return type(self)(self.fget, self.fset, fdel, self.__doc__)

# 3. 범위 검증 디스크립터
class RangeField:
    def __init__(self, min_val=None, max_val=None):
        self.min_val = min_val
        self.max_val = max_val

    def __set_name__(self, owner, name):
        self.name = name
        self.storage = f"_{name}"

    def __get__(self, obj, objtype=None):
        if obj is None: return self
        return getattr(obj, self.storage, None)

    def __set__(self, obj, value):
        if self.min_val is not None and value < self.min_val:
            raise ValueError(f"{self.name}: 최솟값 {self.min_val}")
        if self.max_val is not None and value > self.max_val:
            raise ValueError(f"{self.name}: 최댓값 {self.max_val}")
        setattr(obj, self.storage, value)

class Product:
    price = RangeField(min_val=0)
    quantity = RangeField(min_val=0, max_val=10000)
    discount = RangeField(min_val=0, max_val=100)

product = Product()
product.price = 10000      # ✅
product.discount = 50      # ✅
# product.price = -100     # ❌ ValueError!
# product.discount = 150   # ❌ ValueError!

# 4. 캐싱 디스크립터 (cached_property 구현)
class CachedProperty:
    """한 번 계산하면 캐시하는 디스크립터."""

    def __init__(self, func):
        self.func = func
        self.attrname = None
        self.__doc__ = func.__doc__

    def __set_name__(self, owner, name):
        self.attrname = name

    def __get__(self, obj, objtype=None):
        if obj is None: return self
        # 인스턴스 __dict__에 직접 저장 → 다음 접근은 디스크립터 안 거침
        value = self.func(obj)
        obj.__dict__[self.attrname] = value
        return value

class DataAnalysis:
    def __init__(self, data):
        self.data = data

    @CachedProperty
    def statistics(self):
        """무거운 계산 (한 번만 실행됨)."""
        print("통계 계산 중...")
        return {
            "mean": sum(self.data) / len(self.data),
            "max": max(self.data),
            "min": min(self.data),
        }

analysis = DataAnalysis([1, 2, 3, 4, 5])
print(analysis.statistics)  # "통계 계산 중..." 출력
print(analysis.statistics)  # 캐시 반환 (출력 없음)
```

디스크립터 우선순위:
1. **데이터 디스크립터** (`__get__` + `__set__`) → 인스턴스 `__dict__`보다 우선
2. **인스턴스 `__dict__`**
3. **비데이터 디스크립터** (`__get__`만) → `__dict__`보다 후순위

이것이 `property`가 인스턴스 변수보다 우선하는 이유이고, `cached_property`가 `__dict__`에 직접 저장해서 자신을 가리는 트릭을 쓰는 이유입니다.

파이썬 객체 생성의 3단계를 정확히 설명합니다.

```python
# ═══ 객체 생성 과정 ═══
# MyClass(args) 호출 시:
# 1. MyClass.__new__(cls, args)  → 인스턴스 생성 (메모리 할당)
# 2. MyClass.__init__(self, args) → 인스턴스 초기화 (속성 설정)
# 3. instance(args) → __call__ 호출 (인스턴스를 함수처럼 사용)

class Lifecycle:
    def __new__(cls, *args, **kwargs):
        """인스턴스 생성 (메모리 할당). cls를 받음."""
        print(f"1. __new__: 인스턴스 생성 (cls={cls.__name__})")
        instance = super().__new__(cls)  # 실제 메모리 할당
        return instance  # 반드시 인스턴스 반환!

    def __init__(self, name):
        """인스턴스 초기화. self를 받음."""
        print(f"2. __init__: 초기화 (self={id(self)})")
        self.name = name

    def __call__(self, *args):
        """인스턴스를 함수처럼 호출."""
        print(f"3. __call__: 호출됨 (args={args})")
        return f"{self.name} 실행"

obj = Lifecycle("테스트")
# 출력:
# 1. __new__: 인스턴스 생성 (cls=Lifecycle)
# 2. __init__: 초기화 (self=140234567890)

result = obj("인자1", "인자2")
# 출력:
# 3. __call__: 호출됨 (args=('인자1', '인자2'))

# ═══ __new__의 실무 활용 ═══

# 1. 싱글톤
class Singleton:
    _instance = None

    def __new__(cls, *args, **kwargs):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
        return cls._instance

    def __init__(self, value=None):
        # 주의: 매 호출마다 실행됨!
        if not hasattr(self, "_initialized"):
            self.value = value
            self._initialized = True

s1 = Singleton("첫 번째")
s2 = Singleton("두 번째")
print(s1 is s2)       # True
print(s1.value)        # "첫 번째" (두 번째 호출에서 덮어쓰지 않음)

# 2. 불변 객체 (int, str, tuple은 __new__에서 값 설정)
class FrozenPoint(tuple):
    def __new__(cls, x, y):
        return super().__new__(cls, (x, y))

    @property
    def x(self): return self[0]

    @property
    def y(self): return self[1]

p = FrozenPoint(3, 4)
print(p.x, p.y)   # 3 4
# p[0] = 5  # ❌ TypeError! (tuple은 불변)

# 3. 팩토리 패턴 (다른 클래스 반환 가능!)
class Animal:
    def __new__(cls, species, name):
        if species == "dog":
            return super().__new__(Dog)
        elif species == "cat":
            return super().__new__(Cat)
        return super().__new__(cls)

class Dog(Animal):
    def speak(self): return "멍멍"

class Cat(Animal):
    def speak(self): return "야옹"

animal = Animal("dog", "바둑이")
print(type(animal))     # <class 'Dog'>
print(animal.speak())   # "멍멍"

# ═══ __call__의 실무 활용 ═══

# 1. 설정 가능한 데코레이터
class retry:
    def __init__(self, max_attempts=3, delay=1.0):
        self.max_attempts = max_attempts
        self.delay = delay

    def __call__(self, func):
        import functools, time
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            for attempt in range(1, self.max_attempts + 1):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    if attempt == self.max_attempts:
                        raise
                    time.sleep(self.delay * attempt)
        return wrapper

@retry(max_attempts=5, delay=0.5)
def unstable_api_call():
    ...

# 2. 전략 패턴
class Validator:
    def __init__(self, rules: list):
        self.rules = rules

    def __call__(self, value):
        errors = []
        for rule in self.rules:
            error = rule(value)
            if error:
                errors.append(error)
        return errors if errors else None

# 규칙 정의
def min_length(n):
    def check(v):
        if len(v) < n: return f"{n}자 이상이어야 합니다"
    return check

def has_digit(v):
    if not any(c.isdigit() for c in v): return "숫자를 포함해야 합니다"

# 검증기 생성
validate_password = Validator([min_length(8), has_digit])
errors = validate_password("abc")
# ['8자 이상이어야 합니다', '숫자를 포함해야 합니다']
```

요약:
| 메서드 | 시점 | 인자 | 용도 |
|--------|------|------|------|
| `__new__` | 인스턴스 **생성** | `cls` | 싱글톤, 불변객체, 팩토리 |
| `__init__` | 인스턴스 **초기화** | `self` | 속성 설정 (가장 흔함) |
| `__call__` | 인스턴스 **호출** | `self` | 데코레이터, 전략패턴, 콜백 |

React 리렌더링의 원인과 해결법을 깊이 파봅니다.

```tsx
// ═══ 리렌더링이 일어나는 3가지 원인 ═══
// 1. state 변경
// 2. 부모 컴포넌트 리렌더
// 3. context 값 변경

// ═══ 문제 1: 부모 리렌더 → 모든 자식 리렌더 ═══
// ❌ 부모 state 변경 시 ExpensiveList도 리렌더!
function Parent() {
  const [count, setCount] = useState(0);

  return (
    <div>
      <button onClick={() => setCount(c => c + 1)}>
        클릭: {count}
      </button>
      {/* count와 무관한데 매번 리렌더됨! */}
      <ExpensiveList items={staticItems} />
    </div>
  );
}

// ✅ 해결 1: React.memo
const ExpensiveList = React.memo(function ExpensiveList({
  items,
}: {
  items: Item[];
}) {
  console.log("렌더링!"); // props 변경 시만 출력
  return (
    <ul>
      {items.map((item) => (
        <li key={item.id}>{item.name}</li>
      ))}
    </ul>
  );
});

// ✅ 해결 2: 컴포지션 패턴 (state를 아래로 내림)
function Parent() {
  return (
    <div>
      <CounterButton /> {/* state가 여기 안에만 */}
      <ExpensiveList items={staticItems} /> {/* 리렌더 안 됨! */}
    </div>
  );
}

function CounterButton() {
  const [count, setCount] = useState(0);
  return <button onClick={() => setCount(c => c + 1)}>클릭: {count}</button>;
}

// ═══ 문제 2: 인라인 객체/함수가 매번 새 참조 ═══
// ❌ 매 렌더마다 새 객체 → memo 무효화!
function Parent() {
  const [count, setCount] = useState(0);

  return (
    <Child
      style={{ color: "red" }}           // ❌ 매번 새 객체!
      onClick={() => console.log("hi")}  // ❌ 매번 새 함수!
      config={{ theme: "dark" }}          // ❌ 매번 새 객체!
    />
  );
}

// ✅ useMemo + useCallback
function Parent() {
  const [count, setCount] = useState(0);

  const style = useMemo(() => ({ color: "red" }), []);
  const handleClick = useCallback(() => console.log("hi"), []);
  const config = useMemo(() => ({ theme: "dark" }), []);

  return <Child style={style} onClick={handleClick} config={config} />;
}

// ═══ 문제 3: Context 변경 → 모든 소비자 리렌더 ═══
// ❌ theme 변경 시 UserInfo도 리렌더!
const AppContext = createContext({ theme: "light", user: null });

function App() {
  const [theme, setTheme] = useState("light");
  const [user, setUser] = useState(null);

  return (
    <AppContext.Provider value={{ theme, user }}>
      <ThemeToggle />  {/* theme만 사용 */}
      <UserInfo />     {/* user만 사용하는데 theme 변경 시도 리렌더! */}
    </AppContext.Provider>
  );
}

// ✅ 해결: Context 분리
const ThemeContext = createContext("light");
const UserContext = createContext(null);

function App() {
  const [theme, setTheme] = useState("light");
  const [user, setUser] = useState(null);

  return (
    <ThemeContext.Provider value={theme}>
      <UserContext.Provider value={user}>
        <ThemeToggle />  {/* theme 변경 시만 리렌더 */}
        <UserInfo />     {/* user 변경 시만 리렌더 */}
      </UserContext.Provider>
    </ThemeContext.Provider>
  );
}

// ═══ 문제 4: 리스트 렌더링 최적화 ═══
// ❌ key={index} → 순서 변경 시 전체 리렌더
{items.map((item, index) => <Item key={index} {...item} />)}

// ✅ key={고유ID} → 변경된 항목만 리렌더
{items.map((item) => <Item key={item.id} {...item} />)}

// ═══ 디버깅: React DevTools Profiler ═══
// 1. React DevTools → Profiler 탭
// 2. "Highlight updates when components render" 활성화
// 3. Record → 조작 → Stop
// 4. 각 컴포넌트의 렌더링 횟수/시간 확인

// why-did-you-render 라이브러리
// 불필요한 리렌더 자동 감지
import React from "react";
if (process.env.NODE_ENV === "development") {
  const whyDidYouRender = require("@welldone-software/why-did-you-render");
  whyDidYouRender(React, { trackAllPureComponents: true });
}
```

리렌더 최적화 우선순위:
1. **컴포지션**: state를 사용하는 곳으로 내리기 (가장 효과적)
2. **Context 분리**: 자주 변하는 값과 안 변하는 값 분리
3. **React.memo**: 순수 컴포넌트에 적용
4. **useMemo/useCallback**: 참조 안정성이 필요할 때만
5. **가상화**: 1000+ 항목 리스트는 `react-window` 사용

Next.js App Router의 캐싱 레이어를 깊이 파봅니다.

```tsx
// ═══ Next.js 4단계 캐싱 ═══
// 1. Request Memoization (같은 렌더에서 중복 요청 제거)
// 2. Data Cache (fetch 결과 서버 캐시)
// 3. Full Route Cache (정적 페이지 캐시)
// 4. Router Cache (클라이언트 라우터 캐시)

// ═══ 1. fetch 캐싱 제어 ═══

// 기본: 영구 캐시 (빌드 시 1회)
const data = await fetch("https://api.example.com/data");
// = fetch(url, { cache: "force-cache" })

// 캐시 안 함 (매 요청마다)
const data = await fetch("https://api.example.com/data", {
  cache: "no-store",
});

// 시간 기반 재검증 (ISR)
const data = await fetch("https://api.example.com/data", {
  next: { revalidate: 60 },  // 60초마다 백그라운드 재생성
});

// 태그 기반 재검증
const data = await fetch("https://api.example.com/posts", {
  next: { tags: ["posts"] },
});

// 서버 액션에서 태그 무효화
"use server";
import { revalidateTag, revalidatePath } from "next/cache";

export async function createPost(formData: FormData) {
  await db.post.create({ data: { ... } });
  revalidateTag("posts");        // 태그로 무효화
  revalidatePath("/blog");       // 경로로 무효화
  revalidatePath("/", "layout"); // 전체 레이아웃 무효화
}

// ═══ 2. unstable_cache (DB 쿼리 캐싱) ═══
import { unstable_cache } from "next/cache";

// fetch가 아닌 DB 쿼리/함수 결과를 캐싱
const getCachedUser = unstable_cache(
  async (userId: string) => {
    return db.user.findUnique({
      where: { id: userId },
      include: { posts: true },
    });
  },
  ["user-by-id"],           // 캐시 키 prefix
  {
    revalidate: 300,         // 5분 TTL
    tags: ["users"],         // 태그 (무효화용)
  }
);

// 사용
const user = await getCachedUser(userId);

// 무효화
revalidateTag("users");

// ═══ 3. 페이지 레벨 캐싱 ═══

// 정적 생성 (빌드 시) → 가장 빠름
// app/blog/[slug]/page.tsx
export async function generateStaticParams() {
  const posts = await db.post.findMany({ select: { slug: true } });
  return posts.map((post) => ({ slug: post.slug }));
}

// ISR (시간 기반 재생성)
export const revalidate = 60;  // 페이지 전체 60초 캐시

// 동적 (매 요청)
export const dynamic = "force-dynamic";

// ═══ 4. 세그먼트별 캐싱 전략 ═══
// app/dashboard/layout.tsx
export const revalidate = 300;  // 대시보드 전체 5분

// app/dashboard/stats/page.tsx
export const revalidate = 10;   // 통계는 10초 (더 자주)

// app/dashboard/settings/page.tsx
export const revalidate = 3600; // 설정은 1시간

// ═══ 5. 온디맨드 재검증 (Webhook) ═══
// app/api/revalidate/route.ts
import { revalidateTag } from "next/cache";
import { NextRequest } from "next/server";

export async function POST(request: NextRequest) {
  const secret = request.headers.get("x-webhook-secret");
  if (secret !== process.env.WEBHOOK_SECRET) {
    return Response.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { tag } = await request.json();
  revalidateTag(tag);
  return Response.json({ revalidated: true, now: Date.now() });
}

// CMS에서 콘텐츠 변경 시 → POST /api/revalidate { tag: "posts" }

// ═══ 6. 캐시 디버깅 ═══

// next.config.ts에서 로깅 활성화
const nextConfig = {
  logging: {
    fetches: {
      fullUrl: true,  // fetch URL + 캐시 상태 로그
    },
  },
};

// 서버 로그에서 확인:
// GET https://api.example.com/data (cache: HIT)
// GET https://api.example.com/users (cache: MISS)
// GET https://api.example.com/posts (cache: SKIP - no-store)

// ═══ 7. 캐싱 전략 조합 ═══

// 예: 블로그 사이트
// - 홈페이지: ISR 60초
// - 블로그 목록: ISR 300초 + 태그("posts")
// - 블로그 상세: 정적 생성 + 태그("post-{slug}")
// - 대시보드: 동적 (no-store)
// - 사용자 프로필: ISR 3600초 + 태그("user-{id}")
// - 검색 결과: 동적 (쿼리 파라미터)
```

캐싱 전략 선택:
| 콘텐츠 유형 | 전략 | revalidate |
|-------------|------|------------|
| 마케팅 페이지 | 정적 (빌드) | false |
| 블로그 글 | ISR + 태그 | 300초 |
| 상품 목록 | ISR + 태그 | 60초 |
| 대시보드 | 동적 | 0 (no-store) |
| 사용자 설정 | ISR + 태그 | 3600초 |
| 검색 결과 | 동적 | 0 |
| API 프록시 | 시간 기반 | 10-60초 |

Suspense와 Streaming SSR로 최적의 로딩 경험을 만듭니다.

```tsx
// ═══ 1. Suspense 기본 원리 ═══
// Suspense = "아직 준비 안 된 것을 기다리는 방법"
// 서버 컴포넌트에서 await → 자동으로 Suspense 경계까지 스트리밍

// app/dashboard/page.tsx
import { Suspense } from "react";

export default function Dashboard() {
  return (
    <div className="grid grid-cols-3 gap-4">
      {/* 각각 독립적으로 로딩 → 빠른 것부터 보여줌 */}
      <Suspense fallback={<StatsSkeleton />}>
        <Stats />     {/* 0.5초 */}
      </Suspense>

      <Suspense fallback={<ChartSkeleton />}>
        <Chart />     {/* 2초 */}
      </Suspense>

      <Suspense fallback={<TableSkeleton />}>
        <RecentUsers /> {/* 1초 */}
      </Suspense>
    </div>
  );
}

// 각 컴포넌트는 독립적으로 데이터 페칭
async function Stats() {
  // 이 await 동안 fallback(스켈레톤) 표시
  const stats = await db.getStats();  // 0.5초
  return (
    <div className="rounded-xl border p-6">
      <h3 className="text-2xl font-bold">{stats.totalUsers.toLocaleString()}</h3>
      <p className="text-gray-500">전체 사용자</p>
    </div>
  );
}

async function Chart() {
  const data = await analyticsService.getMonthlyData();  // 2초
  return <BarChart data={data} />;
}

// ═══ 2. Streaming SSR 동작 원리 ═══
// 1) 서버가 HTML 셸(레이아웃 + 스켈레톤)을 즉시 전송
// 2) 각 Suspense 경계가 완료되면 <script>로 교체 HTML 스트리밍
// 3) 클라이언트에서 React가 스켈레톤을 실제 컨텐츠로 교체

// 사용자 경험:
// 0ms:   셸 + 스켈레톤 3개 표시 (TTFB 즉시)
// 500ms: Stats 컨텐츠로 교체
// 1000ms: RecentUsers 컨텐츠로 교체
// 2000ms: Chart 컨텐츠로 교체

// ═══ 3. loading.tsx (자동 Suspense) ═══
// app/dashboard/loading.tsx
export default function DashboardLoading() {
  return (
    <div className="animate-pulse space-y-4">
      <div className="h-8 w-48 bg-gray-200 rounded" />
      <div className="grid grid-cols-3 gap-4">
        {Array.from({ length: 3 }).map((_, i) => (
          <div key={i} className="h-32 bg-gray-200 rounded-xl" />
        ))}
      </div>
    </div>
  );
}
// → app/dashboard/page.tsx를 자동으로 Suspense로 감쌈

// ═══ 4. 병렬 데이터 페칭 ═══

// ❌ 순차 (워터폴) - 느림!
async function Page() {
  const user = await getUser();        // 1초
  const posts = await getPosts();      // 1초
  const comments = await getComments(); // 1초
  // 총 3초!
}

// ✅ 병렬 (Promise.all) - 빠름!
async function Page() {
  const [user, posts, comments] = await Promise.all([
    getUser(),        // 1초
    getPosts(),       // 1초  → 동시 실행
    getComments(),    // 1초
  ]);
  // 총 1초!
}

// ✅ 더 좋은 패턴: Suspense로 점진적 표시
async function Page() {
  const user = await getUser();  // 이건 빠르니까 먼저

  return (
    <div>
      <h1>{user.name}</h1>
      <Suspense fallback={<PostsSkeleton />}>
        <Posts userId={user.id} />  {/* 별도 스트리밍 */}
      </Suspense>
      <Suspense fallback={<CommentsSkeleton />}>
        <Comments userId={user.id} />  {/* 별도 스트리밍 */}
      </Suspense>
    </div>
  );
}

// ═══ 5. Error Boundary + Suspense ═══
// app/dashboard/error.tsx
"use client";

export default function DashboardError({
  error,
  reset,
}: {
  error: Error & { digest?: string };
  reset: () => void;
}) {
  return (
    <div className="p-8 text-center">
      <h2 className="text-xl font-bold text-red-500">오류 발생</h2>
      <p className="mt-2 text-gray-600">{error.message}</p>
      <button
        onClick={reset}
        className="mt-4 rounded-lg bg-blue-600 px-4 py-2 text-white"
      >
        다시 시도
      </button>
    </div>
  );
}

// ═══ 6. useOptimistic (낙관적 업데이트) ═══
"use client";
import { useOptimistic } from "react";

function TodoList({ todos, addTodo }: Props) {
  const [optimisticTodos, addOptimisticTodo] = useOptimistic(
    todos,
    (state, newTodo: string) => [
      ...state,
      { id: crypto.randomUUID(), text: newTodo, pending: true },
    ]
  );

  async function handleSubmit(formData: FormData) {
    const text = formData.get("text") as string;
    addOptimisticTodo(text);     // 즉시 UI 업데이트
    await addTodo(text);         // 서버 액션 (실패 시 자동 롤백)
  }

  return (
    <form action={handleSubmit}>
      <input name="text" />
      <ul>
        {optimisticTodos.map((todo) => (
          <li key={todo.id} className={todo.pending ? "opacity-50" : ""}>
            {todo.text}
          </li>
        ))}
      </ul>
    </form>
  );
}
```

Suspense/Streaming 핵심:
- **Suspense 경계**: 독립적으로 로딩/에러 처리
- **Streaming SSR**: 빠른 것부터 스트리밍 → TTFB 최소화
- **병렬 페칭**: `Promise.all` 또는 Suspense 분리
- **낙관적 업데이트**: 서버 응답 전에 UI 먼저 반영
- **error.tsx**: Suspense 경계별 에러 처리

Server Actions의 고급 패턴과 실무 활용법입니다.

```tsx
// ═══ 1. 기본 Server Action ═══
// app/actions/user.ts
"use server";

import { z } from "zod";
import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";
import { auth } from "@/auth";

// 입력 검증 스키마
const createUserSchema = z.object({
  name: z.string().min(2, "이름은 2자 이상"),
  email: z.string().email("올바른 이메일을 입력하세요"),
  role: z.enum(["user", "admin"]).default("user"),
});

// 타입 안전한 액션 결과
type ActionResult<T = void> =
  | { success: true; data: T }
  | { success: false; error: string; fieldErrors?: Record<string, string[]> };

export async function createUser(
  prevState: ActionResult<User> | null,
  formData: FormData,
): Promise<ActionResult<User>> {
  // 인증 확인
  const session = await auth();
  if (!session || session.user.role !== "admin") {
    return { success: false, error: "권한이 없습니다" };
  }

  // 입력 검증
  const parsed = createUserSchema.safeParse({
    name: formData.get("name"),
    email: formData.get("email"),
    role: formData.get("role"),
  });

  if (!parsed.success) {
    return {
      success: false,
      error: "입력값 오류",
      fieldErrors: parsed.error.flatten().fieldErrors,
    };
  }

  // DB 저장
  try {
    const user = await db.user.create({ data: parsed.data });
    revalidatePath("/admin/users");
    return { success: true, data: user };
  } catch (e) {
    if (e.code === "P2002") {
      return { success: false, error: "이미 가입된 이메일입니다" };
    }
    return { success: false, error: "서버 오류가 발생했습니다" };
  }
}

// ═══ 2. useActionState (React 19) ═══
"use client";
import { useActionState } from "react";
import { createUser } from "@/app/actions/user";

function CreateUserForm() {
  const [state, formAction, isPending] = useActionState(createUser, null);

  return (
    <form action={formAction} className="space-y-4">
      <div>
        <label htmlFor="name">이름</label>
        <input
          id="name"
          name="name"
          className={cn("input", state?.fieldErrors?.name && "border-red-500")}
        />
        {state?.fieldErrors?.name?.map((err) => (
          <p key={err} className="text-sm text-red-500">{err}</p>
        ))}
      </div>

      <div>
        <label htmlFor="email">이메일</label>
        <input id="email" name="email" type="email" className="input" />
        {state?.fieldErrors?.email?.map((err) => (
          <p key={err} className="text-sm text-red-500">{err}</p>
        ))}
      </div>

      {state?.error && !state.success && (
        <div className="rounded-lg bg-red-50 p-3 text-red-500">{state.error}</div>
      )}

      {state?.success && (
        <div className="rounded-lg bg-green-50 p-3 text-green-500">
          사용자가 생성되었습니다!
        </div>
      )}

      <button
        type="submit"
        disabled={isPending}
        className="rounded-lg bg-blue-600 px-4 py-2 text-white disabled:opacity-50"
      >
        {isPending ? "생성 중..." : "사용자 생성"}
      </button>
    </form>
  );
}

// ═══ 3. 파일 업로드 Server Action ═══
"use server";

export async function uploadAvatar(formData: FormData): Promise<ActionResult<string>> {
  const session = await auth();
  if (!session) return { success: false, error: "로그인 필요" };

  const file = formData.get("avatar") as File;
  if (!file || file.size === 0) {
    return { success: false, error: "파일을 선택하세요" };
  }

  // 검증
  if (file.size > 5 * 1024 * 1024) {
    return { success: false, error: "5MB 이하 파일만 가능합니다" };
  }
  if (!["image/jpeg", "image/png", "image/webp"].includes(file.type)) {
    return { success: false, error: "JPG, PNG, WebP만 가능합니다" };
  }

  // S3 업로드
  const buffer = Buffer.from(await file.arrayBuffer());
  const key = `avatars/${session.user.id}/${Date.now()}.${file.type.split("/")[1]}`;

  await s3.putObject({
    Bucket: "hwarang-uploads",
    Key: key,
    Body: buffer,
    ContentType: file.type,
  });

  const url = `https://cdn.hwarang.ai/${key}`;

  // DB 업데이트
  await db.user.update({
    where: { id: session.user.id },
    data: { avatarUrl: url },
  });

  revalidatePath("/profile");
  return { success: true, data: url };
}

// ═══ 4. 낙관적 업데이트 + Server Action ═══
"use client";

function LikeButton({ postId, initialLiked, initialCount }: Props) {
  const [liked, setLiked] = useState(initialLiked);
  const [count, setCount] = useState(initialCount);

  async function handleLike() {
    // 낙관적 업데이트 (즉시 UI 반영)
    const newLiked = !liked;
    setLiked(newLiked);
    setCount((c) => (newLiked ? c + 1 : c - 1));

    try {
      await toggleLike(postId);  // Server Action
    } catch {
      // 실패 시 롤백
      setLiked(!newLiked);
      setCount((c) => (newLiked ? c - 1 : c + 1));
      toast.error("좋아요 처리에 실패했습니다");
    }
  }

  return (
    <button onClick={handleLike} className="flex items-center gap-1">
      <HeartIcon className={liked ? "fill-red-500 text-red-500" : "text-gray-400"} />
      <span>{count}</span>
    </button>
  );
}

// ═══ 5. Server Action에서 redirect ═══
"use server";

export async function deleteUser(userId: string) {
  const session = await auth();
  if (session?.user.role !== "admin") {
    throw new Error("권한 없음");
  }

  await db.user.delete({ where: { id: userId } });
  revalidatePath("/admin/users");
  redirect("/admin/users");  // 리다이렉트 (try/catch 밖에서!)
}
```

Server Actions 핵심:
- **폼 + 검증**: `useActionState` + Zod
- **파일 업로드**: FormData에서 File 추출
- **낙관적 업데이트**: 즉시 UI → 실패 시 롤백
- **캐시 무효화**: `revalidatePath` / `revalidateTag`
- **리다이렉트**: `redirect()` (try/catch 밖에서)
- **인증 확인**: 모든 액션에서 `auth()` 체크

useEffect의 흔한 실수와 올바른 패턴을 깊이 파봅니다.

```tsx
// ═══ 함정 1: 불필요한 useEffect ═══

// ❌ 파생 상태를 useEffect로 동기화
function SearchResults({ items, query }) {
  const [filteredItems, setFilteredItems] = useState([]);

  useEffect(() => {
    setFilteredItems(items.filter(item =>
      item.name.includes(query)
    ));
  }, [items, query]);  // 불필요한 리렌더 유발!

  return <List items={filteredItems} />;
}

// ✅ useMemo로 계산 (리렌더 없음)
function SearchResults({ items, query }) {
  const filteredItems = useMemo(
    () => items.filter(item => item.name.includes(query)),
    [items, query]
  );

  return <List items={filteredItems} />;
}

// ═══ 함정 2: 이벤트 핸들러 대신 useEffect ═══

// ❌ 제출 후 처리를 useEffect로
function Form() {
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    if (submitted) {
      sendAnalytics("form_submitted");
      showToast("저장 완료!");
      setSubmitted(false);
    }
  }, [submitted]);

  return <button onClick={() => setSubmitted(true)}>제출</button>;
}

// ✅ 이벤트 핸들러에서 직접 처리
function Form() {
  async function handleSubmit() {
    await saveData();
    sendAnalytics("form_submitted");
    showToast("저장 완료!");
  }

  return <button onClick={handleSubmit}>제출</button>;
}

// ═══ 함정 3: 클린업 누락 (메모리 누수) ═══

// ❌ 클린업 없음 → 컴포넌트 언마운트 후에도 실행!
function Chat({ roomId }) {
  useEffect(() => {
    const ws = new WebSocket(`/ws/${roomId}`);
    ws.onmessage = (event) => {
      setMessages(prev => [...prev, JSON.parse(event.data)]);
    };
    // 클린업 없음! → 메모리 누수 + 에러
  }, [roomId]);
}

// ✅ 클린업 함수 반환
function Chat({ roomId }) {
  useEffect(() => {
    const ws = new WebSocket(`/ws/${roomId}`);
    ws.onmessage = (event) => {
      setMessages(prev => [...prev, JSON.parse(event.data)]);
    };

    return () => {
      ws.close();  // roomId 변경 또는 언마운트 시 정리
    };
  }, [roomId]);
}

// ═══ 함정 4: 경쟁 조건 (Race Condition) ═══

// ❌ 빠르게 입력 변경 시 이전 요청이 나중에 도착할 수 있음
function Search({ query }) {
  const [results, setResults] = useState([]);

  useEffect(() => {
    fetch(`/api/search?q=${query}`)
      .then(res => res.json())
      .then(data => setResults(data));  // 이전 query의 결과가 덮어쓸 수 있음!
  }, [query]);
}

// ✅ cleanup으로 이전 요청 무시
function Search({ query }) {
  const [results, setResults] = useState([]);

  useEffect(() => {
    let cancelled = false;

    fetch(`/api/search?q=${query}`)
      .then(res => res.json())
      .then(data => {
        if (!cancelled) {  // 취소되지 않은 경우만 반영
          setResults(data);
        }
      });

    return () => {
      cancelled = true;  // 이전 요청 결과 무시
    };
  }, [query]);
}

// ✅✅ 더 좋은 방법: AbortController
function Search({ query }) {
  const [results, setResults] = useState([]);

  useEffect(() => {
    const controller = new AbortController();

    fetch(`/api/search?q=${query}`, { signal: controller.signal })
      .then(res => res.json())
      .then(data => setResults(data))
      .catch(err => {
        if (err.name !== "AbortError") throw err;
      });

    return () => controller.abort();  // 이전 요청 자체를 취소
  }, [query]);
}

// ═══ 함정 5: 무한 루프 ═══

// ❌ 객체를 의존성에 넣으면 매 렌더마다 실행!
function Component({ id }) {
  const options = { id, limit: 20 };  // 매번 새 객체!

  useEffect(() => {
    fetchData(options);
  }, [options]);  // 무한 루프!
}

// ✅ 원시값을 의존성으로 사용
function Component({ id }) {
  useEffect(() => {
    fetchData({ id, limit: 20 });
  }, [id]);  // id가 바뀔 때만
}

// ═══ useEffect가 적절한 경우 ═══
// 1. 외부 시스템과 동기화 (WebSocket, EventSource, DOM API)
// 2. 타이머/인터벌
// 3. 브라우저 이벤트 리스너 (resize, scroll, online/offline)
// 4. 서드파티 라이브러리 초기화 (차트, 지도)

// 올바른 예: 윈도우 리사이즈 감지
function useWindowSize() {
  const [size, setSize] = useState({ width: 0, height: 0 });

  useEffect(() => {
    function handleResize() {
      setSize({ width: window.innerWidth, height: window.innerHeight });
    }

    handleResize();  // 초기값
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);  // 마운트/언마운트에만

  return size;
}
```

useEffect 판단 기준:
| 상황 | useEffect? | 대안 |
|------|-----------|------|
| 파생 상태 계산 | ❌ | `useMemo` |
| 이벤트 후 처리 | ❌ | 이벤트 핸들러 |
| 외부 시스템 동기화 | ✅ | - |
| API 데이터 페칭 | ⚠️ | TanStack Query / Server Component |
| DOM 측정 | ✅ | `useLayoutEffect` |
| 타이머 | ✅ | - |

