    "JetBrains Mono",
    "Fira Code",
    "D2Coding",
    monospace;
}

/* 2. 타입 스케일 (1.25 비율) */
/*
  Display:  2.488rem (40px)
  H1:       2.074rem (33px)
  H2:       1.728rem (28px)
  H3:       1.44rem  (23px)
  H4:       1.2rem   (19px)
  Body:     1rem     (16px)
  Small:    0.833rem (13px)
  Caption:  0.694rem (11px)
*/

/* 3. 가독성 최적 설정 */
body {
  font-size: 16px;           /* 기본 크기 */
  line-height: 1.6;          /* 본문 줄 간격 */
  letter-spacing: -0.01em;   /* 한국어 자간 미세 조정 */
  word-break: keep-all;      /* 한국어 단어 단위 줄바꿈 */
  overflow-wrap: break-word;
}

h1, h2, h3, h4 {
  line-height: 1.3;          /* 제목은 좁은 줄 간격 */
  letter-spacing: -0.02em;   /* 제목은 좁은 자간 */
  font-weight: 700;
}

p {
  max-width: 70ch;           /* 최적 읽기 폭 (한 줄 70자) */
}

/* 4. 반응형 타이포그래피 */
html {
  /* 뷰포트에 따라 자동 조정 */
  font-size: clamp(14px, 1vw + 10px, 18px);
}

/* 또는 미디어 쿼리 */
@media (max-width: 768px) {
  h1 { font-size: 1.75rem; }
  h2 { font-size: 1.5rem; }
  body { font-size: 15px; }
}
