  50% { transform: translateY(-10px); }
}

h2 { font-size: 1.5rem; color: #e2e8f0; margin-bottom: 1rem; }
p { color: #94a3b8; max-width: 400px; margin: 0 auto 2rem; line-height: 1.6; }

