## 핵심: Server-Sent Events(SSE) + 차트

```tsx
// app/dashboard/page.tsx
"use client";
import { useState, useEffect } from "react";

interface 메트릭 {
  cpu: number;
  memory: number;
  requests: number;
  errors: number;
  responseTime: number;
  timestamp: string;
}

export default function 대시보드() {
  const [메트릭들, 메트릭설정] = useState<메트릭[]>([]);
  const [현재, 현재설정] = useState<메트릭 | null>(null);

  useEffect(() => {
    // SSE 연결 (실시간 데이터 수신)
    const eventSource = new EventSource("/api/metrics/stream");

    eventSource.onmessage = (event) => {
      const 데이터: 메트릭 = JSON.parse(event.data);
      현재설정(데이터);
      메트릭설정(이전 => [...이전.slice(-59), 데이터]); // 최근 60개
    };

    return () => eventSource.close();
  }, []);

  if (!현재) return <div className="p-8 text-center">연결 중...</div>;

  return (
    <div className="p-6 space-y-6">
      <h1 className="text-2xl font-bold">실시간 모니터링</h1>

      {/* 핵심 지표 카드 */}
      <div className="grid grid-cols-4 gap-4">
        <MetricCard title="CPU" value={`${현재.cpu}%`}
          color={현재.cpu > 80 ? "red" : 현재.cpu > 50 ? "yellow" : "green"} />
        <MetricCard title="메모리" value={`${현재.memory}%`}
          color={현재.memory > 80 ? "red" : "green"} />
        <MetricCard title="요청/초" value={현재.requests.toString()} color="blue" />
        <MetricCard title="응답시간" value={`${현재.responseTime}ms`}
          color={현재.responseTime > 1000 ? "red" : "green"} />
      </div>

      {/* 실시간 차트 (최근 60초) */}
      <div className="bg-white rounded-xl border p-4">
        <h3 className="font-semibold mb-4">CPU / 메모리 추이 (60초)</h3>
        <div className="h-64 flex items-end gap-1">
          {메트릭들.map((m, i) => (
            <div key={i} className="flex-1 flex flex-col gap-1">
              <div
                className="bg-blue-500 rounded-t"
                style={{ height: `${m.cpu * 2}px` }}
                title={`CPU ${m.cpu}%`}
              />
              <div
                className="bg-green-500 rounded-t"
                style={{ height: `${m.memory * 2}px` }}
                title={`MEM ${m.memory}%`}
              />
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function MetricCard({ title, value, color }: { title: string; value: string; color: string }) {
  const colors = {
    red: "border-red-500 text-red-600",
    yellow: "border-yellow-500 text-yellow-600",
    green: "border-green-500 text-green-600",
    blue: "border-blue-500 text-blue-600",
  };
  return (
    <div className={`rounded-xl border-2 p-4 ${colors[color]}`}>
      <div className="text-sm opacity-70">{title}</div>
      <div className="text-3xl font-bold">{value}</div>
    </div>
  );
}
```

## SSE 엔드포인트

```typescript
// app/api/metrics/stream/route.ts
export async function GET() {
  const encoder = new TextEncoder();

  const stream = new ReadableStream({
    start(controller) {
      const interval = setInterval(() => {
        const 메트릭 = {
          cpu: Math.round(Math.random() * 100),
          memory: Math.round(50 + Math.random() * 40),
          requests: Math.round(Math.random() * 500),
          errors: Math.round(Math.random() * 5),
          responseTime: Math.round(50 + Math.random() * 200),
          timestamp: new Date().toISOString(),
        };
        controller.enqueue(encoder.encode(`data: ${JSON.stringify(메트릭)}\n\n`));
      }, 1000); // 1초마다

      // 정리
      setTimeout(() => {
        clearInterval(interval);
        controller.close();
      }, 3600000); // 1시간 후 종료
    },
  });

  return new Response(stream, {
    headers: {
      "Content-Type": "text/event-stream",
      "Cache-Control": "no-cache",
      Connection: "keep-alive",
    },
  });
}
```

SSE는 WebSocket보다 간단하고, 서버→클라이언트 단방향 실시간 데이터에 적합합니다.

Elasticsearch는 전문 검색과 분석에 특화된 엔진입니다.

```python
# ═══ Elasticsearch 8.x ═══
from elasticsearch import AsyncElasticsearch

es = AsyncElasticsearch(
    "https://localhost:9200",
    api_key="xxx",
)

# ═══ 1. 인덱스 생성 (한국어 형태소 분석) ═══
await es.indices.create(
    index="posts",
    body={
        "settings": {
            "analysis": {
                "analyzer": {
                    "korean": {
                        "type": "custom",
                        "tokenizer": "nori_tokenizer",  # 한국어 형태소
                        "filter": [
                            "nori_part_of_speech",
                            "lowercase",
                        ],
                    },
                },
            },
        },
        "mappings": {
            "properties": {
                "title": {
                    "type": "text",
                    "analyzer": "korean",
                    "fields": {
                        "keyword": {"type": "keyword"},  # 정렬/집계용
                    },
                },
                "content": {"type": "text", "analyzer": "korean"},
                "tags": {"type": "keyword"},
                "author": {"type": "keyword"},
                "created_at": {"type": "date"},
                "view_count": {"type": "integer"},
                "embedding": {
                    "type": "dense_vector",  # 벡터 검색
                    "dims": 1024,
                    "index": True,
                    "similarity": "cosine",
                },
            },
        },
    },
)

# ═══ 2. 문서 색인 ═══
await es.index(
    index="posts",
    id="1",
    document={
        "title": "파이썬 비동기 프로그래밍",
        "content": "asyncio를 활용한 효율적인 서버 개발...",
        "tags": ["python", "asyncio"],
        "author": "홍길동",
        "created_at": "2025-04-20T10:00:00Z",
        "view_count": 150,
    },
)

# 벌크 색인 (대량)
from elasticsearch.helpers import async_bulk

actions = [
    {
        "_index": "posts",
        "_id": str(post["id"]),
        "_source": post,
    }
    for post in posts
]
await async_bulk(es, actions, chunk_size=500)

# ═══ 3. 검색 ═══
# 기본 검색
result = await es.search(
    index="posts",
    body={
        "query": {
            "multi_match": {
                "query": "파이썬 비동기",
                "fields": ["title^3", "content"],  # 제목 3배 가중치
                "type": "best_fields",
            },
        },
        "highlight": {
            "fields": {"title": {}, "content": {}},
            "pre_tags": ["<mark>"],
            "post_tags": ["</mark>"],
        },
        "sort": [
            {"_score": "desc"},
            {"created_at": "desc"},
        ],
        "from": 0,
        "size": 20,
    },
)

# 복합 쿼리 (bool)
result = await es.search(
    index="posts",
    body={
        "query": {
            "bool": {
                "must": [
                    {"multi_match": {"query": "파이썬", "fields": ["title", "content"]}},
                ],
                "filter": [
                    {"term": {"author": "홍길동"}},
                    {"range": {"created_at": {"gte": "2025-01-01"}}},
                    {"terms": {"tags": ["python", "asyncio"]}},
                ],
                "must_not": [
                    {"term": {"status": "deleted"}},
                ],
            },
        },
    },
)

# 자동완성 (Suggest)
result = await es.search(
    index="posts",
