```typescript
// ═══ 1. 스키마 설계 ═══
// prisma/schema.prisma

generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

model User {
  id            String   @id @default(cuid())
  email         String   @unique
  name          String
  role          Role     @default(USER)
  hashedPassword String?

  // 관계
  posts         Post[]
  comments      Comment[]
  profile       Profile?

  // 타임스탬프
  createdAt     DateTime @default(now())
  updatedAt     DateTime @updatedAt

  // 인덱스
  @@index([email])
  @@index([role, createdAt(sort: Desc)])
  @@map("users")
}

model Post {
  id        String   @id @default(cuid())
  title     String
  content   String
  published Boolean  @default(false)
  viewCount Int      @default(0)
  tags      String[]

  author    User     @relation(fields: [authorId], references: [id], onDelete: Cascade)
  authorId  String
  comments  Comment[]

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  // 전문 검색 인덱스
  @@index([title, content])
  @@map("posts")
}

enum Role {
  USER
  ADMIN
  EDITOR
}

// ═══ 2. 고급 쿼리 ═══
import { PrismaClient, Prisma } from "@prisma/client";

const prisma = new PrismaClient({
  log: process.env.NODE_ENV === "development" ? ["query", "warn", "error"] : ["error"],
});

// 관계 포함 + 필터 + 정렬 + 페이지네이션
async function getUsers(params: {
  page: number;
  limit: number;
  search?: string;
  role?: Role;
}) {
  const where: Prisma.UserWhereInput = {
    ...(params.search && {
      OR: [
        { name: { contains: params.search, mode: "insensitive" } },
        { email: { contains: params.search, mode: "insensitive" } },
      ],
    }),
    ...(params.role && { role: params.role }),
  };

  const [users, total] = await prisma.$transaction([
    prisma.user.findMany({
      where,
      include: {
        profile: true,
        _count: { select: { posts: true, comments: true } },
      },
      orderBy: { createdAt: "desc" },
      skip: (params.page - 1) * params.limit,
      take: params.limit,
    }),
    prisma.user.count({ where }),
  ]);

  return { users, total, totalPages: Math.ceil(total / params.limit) };
}

// ═══ 3. 트랜잭션 ═══
// Interactive 트랜잭션 (복잡한 로직)
async function transferPoints(fromId: string, toId: string, amount: number) {
  return prisma.$transaction(async (tx) => {
    const sender = await tx.user.findUnique({ where: { id: fromId } });
    if (!sender || sender.points < amount) {
      throw new Error("포인트 부족");
    }

    await tx.user.update({
      where: { id: fromId },
      data: { points: { decrement: amount } },
    });

    await tx.user.update({
      where: { id: toId },
      data: { points: { increment: amount } },
    });

    await tx.pointHistory.create({
      data: { fromId, toId, amount, type: "TRANSFER" },
    });
  });
}

// ═══ 4. 원시 SQL (복잡한 쿼리) ═══
// 타입 안전한 원시 쿼리
const result = await prisma.$queryRaw<{ month: Date; count: bigint }[]>`
  SELECT
    DATE_TRUNC('month', created_at) AS month,
    COUNT(*) AS count
  FROM posts
  WHERE published = true
    AND created_at >= NOW() - INTERVAL '12 months'
  GROUP BY month
  ORDER BY month DESC
`;

// ═══ 5. Middleware (로깅, 소프트 삭제) ═══
// 소프트 삭제 미들웨어
prisma.$use(async (params, next) => {
  // DELETE → UPDATE (deleted_at 설정)
  if (params.action === "delete") {
    params.action = "update";
    params.args.data = { deletedAt: new Date() };
  }

  // findMany → 삭제된 항목 제외
  if (params.action === "findMany" || params.action === "findFirst") {
    if (!params.args.where) params.args.where = {};
    params.args.where.deletedAt = null;
  }

  return next(params);
});

// ═══ 6. 확장 (Extension) ═══
const xprisma = prisma.$extends({
  model: {
    user: {
      async findByEmail(email: string) {
        return prisma.user.findUnique({ where: { email } });
      },
      async softDelete(id: string) {
        return prisma.user.update({
          where: { id },
          data: { deletedAt: new Date() },
        });
      },
    },
  },
  query: {
    $allOperations({ operation, args, query }) {
      const start = performance.now();
      return query(args).finally(() => {
        const duration = performance.now() - start;
        if (duration > 1000) {
          console.warn(`느린 쿼리: ${operation} (${duration.toFixed(0)}ms)`);
        }
      });
    },
  },
});

// 사용
const user = await xprisma.user.findByEmail("hong@test.com");
await xprisma.user.softDelete("user_123");
```

Prisma 핵심:
- `$transaction` → 원자적 작업
- `include` / `select` → 관계 로딩
- `_count` → 관계 카운트 (서브쿼리 자동)
- Middleware → 공통 로직 (로깅, 소프트삭제)
- Extension → 커스텀 메서드 추가

함수형 프로그래밍(FP)의 핵심 패턴입니다.

```typescript
// ═══ TypeScript 함수형 패턴 ═══

// 1. 순수 함수 (Pure Function) - 같은 입력 → 같은 출력, 부수효과 없음
const calculateTax = (price: number, rate: number): number => price * rate;

// 2. 불변성 (Immutability)
// ❌ 변이 (Mutation)
const addItemBad = (cart: Item[], item: Item) => {
  cart.push(item);  // 원본 변경!
  return cart;
};

// ✅ 불변 (Immutable)
const addItem = (cart: readonly Item[], item: Item): Item[] => [...cart, item];
const removeItem = (cart: readonly Item[], id: string): Item[] =>
  cart.filter((item) => item.id !== id);
const updateItem = (cart: readonly Item[], id: string, updates: Partial<Item>): Item[] =>
  cart.map((item) => (item.id === id ? { ...item, ...updates } : item));

// 3. 고차 함수 (Higher-Order Function)
const withRetry = <T>(fn: () => Promise<T>, maxRetries: number = 3) => {
  return async (): Promise<T> => {
    let lastError: Error;
    for (let i = 0; i < maxRetries; i++) {
      try {
        return await fn();
      } catch (e) {
        lastError = e as Error;
        await new Promise((r) => setTimeout(r, 1000 * (i + 1)));
      }
    }
    throw lastError!;
  };
};

// 사용
const fetchWithRetry = withRetry(() => fetch("/api/data"), 3);

// 4. 함수 합성 (Composition)
const pipe = <T>(...fns: ((arg: T) => T)[]) =>
  (value: T): T => fns.reduce((acc, fn) => fn(acc), value);

const processUser = pipe(
  (user: User) => ({ ...user, name: user.name.trim() }),
  (user: User) => ({ ...user, email: user.email.toLowerCase() }),
  (user: User) => ({ ...user, age: Math.max(0, user.age) }),
);

const result = processUser({ name: " 홍길동 ", email: "HONG@Test.COM", age: -1 });
// { name: "홍길동", email: "hong@test.com", age: 0 }

// 5. 커링 (Currying)
const multiply = (a: number) => (b: number) => a * b;
const double = multiply(2);
const triple = multiply(3);

console.log(double(5));  // 10
console.log(triple(5));  // 15

// 실무 활용: 설정 주입
const createLogger = (prefix: string) => (level: string) => (message: string) =>
  console.log(`[${prefix}] ${level}: ${message}`);

const apiLogger = createLogger("API");
const apiError = apiLogger("ERROR");
apiError("요청 실패");  // [API] ERROR: 요청 실패

// 6. Option/Maybe 패턴 (null 안전)
type Option<T> = { type: "some"; value: T } | { type: "none" };

const some = <T>(value: T): Option<T> => ({ type: "some", value });
const none = <T>(): Option<T> => ({ type: "none" });

const map = <T, U>(opt: Option<T>, fn: (v: T) => U): Option<U> =>
  opt.type === "some" ? some(fn(opt.value)) : none();

const getOrElse = <T>(opt: Option<T>, defaultValue: T): T =>
  opt.type === "some" ? opt.value : defaultValue;

// 사용
const findUser = (id: number): Option<User> =>
  users.has(id) ? some(users.get(id)!) : none();

const userName = getOrElse(
  map(findUser(1), (u) => u.name),
  "알 수 없음"
);
```

