    if (cached) {
      return new Response(cached, {
        headers: { "Content-Type": "application/json", "X-Cache": "HIT" },
      });
    }

    // 원본 서버에서 가져오기
    const response = await fetch(`https://api.hwarang.ai${url.pathname}`);
    const data = await response.text();

    // 캐시 저장 (5분)
    await env.CACHE.put(url.pathname, data, { expirationTtl: 300 });

    return new Response(data, {
      headers: { "Content-Type": "application/json", "X-Cache": "MISS" },
    });
  },
};

// ═══ 4. Edge에서 AI 스트리밍 ═══
export const runtime = "edge";

export async function POST(request: Request) {
  const { messages } = await request.json();

  const response = await fetch("https://api.openai.com/v1/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${process.env.OPENAI_API_KEY}`,
    },
    body: JSON.stringify({ model: "gpt-4o", messages, stream: true }),
  });

  // 스트림 변환 (OpenAI → SSE)
  const transformStream = new TransformStream({
    transform(chunk, controller) {
      controller.enqueue(chunk);
    },
  });

  return new Response(
    response.body!.pipeThrough(transformStream),
    {
      headers: {
        "Content-Type": "text/event-stream",
        "Cache-Control": "no-cache",
      },
    },
  );
}
```

Edge vs Serverless vs Server:
| 항목 | Edge | Serverless | Server |
|------|------|------------|--------|
| 지연 시간 | 최소 (~10ms) | 보통 (~100ms) | 고정 |
| 콜드 스타트 | 거의 없음 | 있음 (~500ms) | 없음 |
| 런타임 | V8 (제한적) | Node.js (풀) | Node.js (풀) |
| DB 접근 | 제한 (HTTP만) | 가능 | 가능 |
| 적합 | 미들웨어, 캐시, A/B | API, 백그라운드 | 무거운 로직 |

Rust의 핵심인 소유권(Ownership)과 빌림(Borrowing) 시스템입니다.

```rust
// ═══ 1. 소유권 (Ownership) ═══
// 규칙: 각 값은 하나의 소유자만 가짐. 소유자가 스코프를 벗어나면 값 해제.

fn main() {
    // String은 힙에 할당 → 소유권 이동(move)
    let s1 = String::from("안녕하세요");
    let s2 = s1;  // s1의 소유권이 s2로 이동
    // println!("{}", s1);  // ❌ 컴파일 에러! s1은 더 이상 유효하지 않음
    println!("{}", s2);     // ✅ OK

    // 복사 가능한 타입 (Copy trait: i32, f64, bool, char)
    let x = 42;
    let y = x;  // 복사됨 (스택 데이터)
    println!("{} {}", x, y);  // ✅ 둘 다 유효

    // clone: 깊은 복사 (명시적)
    let s3 = String::from("복사");
    let s4 = s3.clone();  // 힙 데이터 전체 복사
    println!("{} {}", s3, s4);  // ✅ 둘 다 유효
}

// 함수에 전달하면 소유권 이동
fn takes_ownership(s: String) {
    println!("{}", s);
}  // s가 drop됨

fn gives_ownership() -> String {
    String::from("반환")  // 소유권을 호출자에게 전달
}

// ═══ 2. 빌림 (Borrowing) ═══
// 소유권 이동 없이 참조로 빌림

// 불변 참조 (&T) - 여러 개 동시 가능
fn calculate_length(s: &String) -> usize {
    s.len()
    // s를 수정할 수 없음
}

// 가변 참조 (&mut T) - 동시에 하나만 가능
fn append_text(s: &mut String) {
    s.push_str(" 추가");
}

fn borrowing_example() {
    let mut text = String::from("원본");

    // 불변 참조 여러 개 OK
    let r1 = &text;
    let r2 = &text;
    println!("{} {}", r1, r2);

    // 가변 참조는 하나만
    let r3 = &mut text;
    r3.push_str(" 수정");
    // let r4 = &mut text;  // ❌ 동시에 두 개 불가
    // let r5 = &text;      // ❌ 불변+가변 동시 불가

    println!("{}", r3);
}

// ═══ 3. 라이프타임 ═══
// 참조가 유효한 범위를 명시

// 두 문자열 중 긴 것을 반환
fn longest<'a>(x: &'a str, y: &'a str) -> &'a str {
    if x.len() > y.len() { x } else { y }
}

// 구조체에서 라이프타임
struct Excerpt<'a> {
    content: &'a str,  // 이 참조는 구조체보다 오래 살아야 함
}

impl<'a> Excerpt<'a> {
    fn level(&self) -> i32 {
        3
    }

    // 반환 라이프타임 = self의 라이프타임
    fn announce(&self, announcement: &str) -> &'a str {
        println!("공지: {}", announcement);
        self.content
    }
}

// ═══ 4. 스마트 포인터 ═══
use std::rc::Rc;
use std::cell::RefCell;

// Box: 힙 할당
let boxed = Box::new(42);

// Rc: 참조 카운팅 (여러 소유자)
let shared = Rc::new(String::from("공유 데이터"));
let clone1 = Rc::clone(&shared);
let clone2 = Rc::clone(&shared);
println!("참조 수: {}", Rc::strong_count(&shared));  // 3

// RefCell: 내부 가변성 (런타임 빌림 규칙 검사)
let data = RefCell::new(vec![1, 2, 3]);
data.borrow_mut().push(4);
println!("{:?}", data.borrow());

// Arc: 스레드 안전 Rc (멀티스레드)
use std::sync::Arc;
let thread_safe = Arc::new(vec![1, 2, 3]);
```

소유권 핵심 규칙:
1. 각 값은 **하나의 소유자**만 가짐
2. 소유자가 스코프를 벗어나면 값이 **자동 해제**
3. **불변 참조**: 여러 개 동시 가능 (`&T`)
4. **가변 참조**: 하나만 가능 (`&mut T`), 불변과 동시 불가
5. 참조는 항상 **유효**해야 함 (댕글링 포인터 없음)

