Axum은 Rust의 최신 웹 프레임워크입니다 (Tokio 기반).

```rust
// ═══ Cargo.toml ═══
// [dependencies]
// axum = "0.7"
// tokio = { version = "1", features = ["full"] }
// serde = { version = "1", features = ["derive"] }
// serde_json = "1"
// sqlx = { version = "0.8", features = ["runtime-tokio", "postgres"] }
// tower-http = { version = "0.5", features = ["cors", "trace"] }
// tracing = "0.1"
// tracing-subscriber = "0.3"

use axum::{
    extract::{Path, Query, State, Json},
    http::StatusCode,
    middleware,
    response::IntoResponse,
    routing::{get, post, put, delete},
    Router,
};
use serde::{Deserialize, Serialize};
use sqlx::PgPool;
use std::sync::Arc;
use tower_http::cors::CorsLayer;
use tracing_subscriber;

// ═══ 모델 ═══
#[derive(Debug, Serialize, Deserialize, sqlx::FromRow)]
struct User {
    id: i64,
    name: String,
    email: String,
    created_at: chrono::NaiveDateTime,
}

#[derive(Debug, Deserialize)]
struct CreateUser {
    name: String,
    email: String,
}

#[derive(Debug, Deserialize)]
struct ListParams {
    page: Option<i64>,
    limit: Option<i64>,
    search: Option<String>,
}

// ═══ 앱 상태 ═══
#[derive(Clone)]
struct AppState {
    db: PgPool,
}

// ═══ 핸들러 ═══
async fn list_users(
    State(state): State<AppState>,
    Query(params): Query<ListParams>,
) -> Result<Json<Vec<User>>, AppError> {
    let page = params.page.unwrap_or(1);
    let limit = params.limit.unwrap_or(20).min(100);
    let offset = (page - 1) * limit;

    let users = if let Some(search) = &params.search {
        sqlx::query_as!(
            User,
            r#"SELECT * FROM users WHERE name ILIKE $1 ORDER BY created_at DESC LIMIT $2 OFFSET $3"#,
            format!("%{}%", search), limit, offset
        )
        .fetch_all(&state.db)
        .await?
    } else {
        sqlx::query_as!(
            User,
            "SELECT * FROM users ORDER BY created_at DESC LIMIT $1 OFFSET $2",
            limit, offset
        )
        .fetch_all(&state.db)
        .await?
    };

    Ok(Json(users))
}

async fn get_user(
    State(state): State<AppState>,
    Path(id): Path<i64>,
) -> Result<Json<User>, AppError> {
    let user = sqlx::query_as!(User, "SELECT * FROM users WHERE id = $1", id)
        .fetch_optional(&state.db)
        .await?
        .ok_or(AppError::NotFound(format!("사용자 #{}", id)))?;

    Ok(Json(user))
}

async fn create_user(
    State(state): State<AppState>,
    Json(input): Json<CreateUser>,
) -> Result<(StatusCode, Json<User>), AppError> {
    let user = sqlx::query_as!(
        User,
        "INSERT INTO users (name, email) VALUES ($1, $2) RETURNING *",
        input.name, input.email
    )
    .fetch_one(&state.db)
    .await?;

    Ok((StatusCode::CREATED, Json(user)))
}

async fn delete_user(
    State(state): State<AppState>,
    Path(id): Path<i64>,
) -> Result<StatusCode, AppError> {
    sqlx::query!("DELETE FROM users WHERE id = $1", id)
        .execute(&state.db)
        .await?;

    Ok(StatusCode::NO_CONTENT)
}

async fn health() -> &'static str {
    "OK"
}

// ═══ 라우터 ═══
fn create_router(state: AppState) -> Router {
    Router::new()
        .route("/health", get(health))
        .route("/api/users", get(list_users).post(create_user))
        .route("/api/users/{id}", get(get_user).delete(delete_user))
        .layer(CorsLayer::permissive())
        .with_state(state)
}

// ═══ 메인 ═══
#[tokio::main]
async fn main() -> anyhow::Result<()> {
    tracing_subscriber::init();

    let db = PgPool::connect(&std::env::var("DATABASE_URL")?).await?;
    sqlx::migrate!().run(&db).await?;  // 마이그레이션 실행

    let state = AppState { db };
    let app = create_router(state);

    let listener = tokio::net::TcpListener::bind("0.0.0.0:8080").await?;
    tracing::info!("서버 시작: http://0.0.0.0:8080");
    axum::serve(listener, app).await?;

    Ok(())
}
