  const { page, limit, sort, order, q } = params.data;
  // ...
}

// ═══ 5. 판별 유니온 스키마 ═══
const notificationSchema = z.discriminatedUnion("type", [
  z.object({
    type: z.literal("email"),
    to: z.string().email(),
    subject: z.string(),
    body: z.string(),
  }),
  z.object({
    type: z.literal("sms"),
    phone: z.string().regex(/^01[0-9]-\d{4}-\d{4}$/),
    message: z.string().max(90),
  }),
